$.aCS.sHe(A.aD(["introArc",A.a([new A.aY("In a world where every choice you make carries consequences, you have the ability to shape the fate of this world. Welcome to the EcoShift Chronicles, where what you decide affects whether things stay in sync or go haywire.","\u3042\u3089\u3086\u308b\u9078\u629e\u304c\u7d50\u679c\u3092\u4f34\u3046\u4e16\u754c\u3002\u3042\u306a\u305f\u306f\u3053\u306e\u4e16\u754c\u306e\u904b\u547d\u3092\u5f62\u4f5c\u308b\u529b\u3092\u6301\u3063\u3066\u3044\u307e\u3059\u3002\u30a8\u30b3\u30b7\u30d5\u30c8\u30fb\u30af\u30ed\u30cb\u30af\u30eb\u3078\u3088\u3046\u3053\u305d\u3002\u3042\u306a\u305f\u306e\u6c7a\u5b9a\u304c\u7269\u4e8b\u3092\u8abf\u548c\u3055\u305b\u308b\u304b\u3001\u4e71\u308c\u3055\u305b\u308b\u304b\u3092\u5de6\u53f3\u3057\u307e\u3059\u3002",B.a2,null,null),new A.aY("Ah, welcome to the playground of choices! Every decision holds consequences. But who says you always have to be the hero? Why not embrace the dark side of choices?","\u3042\u3042\u3001\u9078\u629e\u306e\u904a\u3073\u5834\u3078\u3088\u3046\u3053\u305d\uff01\u3059\u3079\u3066\u306e\u6c7a\u65ad\u306b\u306f\u7d50\u679c\u304c\u4f34\u3044\u307e\u3059\u3002\u3057\u304b\u3057\u3001\u3044\u3064\u3082\u30d2\u30fc\u30ed\u30fc\u3067\u3042\u308b\u5fc5\u8981\u304c\u3042\u308b\u3068\u8ab0\u304c\u8a00\u3044\u307e\u3059\u304b\uff1f\u306a\u305c\u9078\u629e\u306e\u6697\u3044\u5074\u9762\u3092\u53d7\u3051\u5165\u308c\u306a\u3044\u306e\u3067\u3059\u304b\uff1f",B.a6,null,null),new A.aY("Embrace the path of balance and watch as the world transforms into a harmonious paradise.","\u30d0\u30e9\u30f3\u30b9\u306e\u9053\u3092\u53d7\u3051\u5165\u308c\u3001\u4e16\u754c\u304c\u8abf\u548c\u306e\u697d\u5712\u306b\u5909\u308f\u308b\u306e\u3092\u898b\u5b88\u3063\u3066\u304f\u3060\u3055\u3044\u3002",B.a2,null,null)],q),"bathroomArc",A.a([new A.aY("[You start to brush your teeth and forgot to turn off the tap]","[\u6b6f\u3092\u78e8\u304d\u59cb\u3081\u3001\u86c7\u53e3\u3092\u9589\u3081\u5fd8\u308c\u3066\u3057\u307e\u3044\u307e\u3057\u305f]",null,null,null),new A.aY("Hey there, buddy! What's a little water waste, right? Convenience is key!","\u3084\u3042\u3001\u53cb\u3088\uff01\u3061\u3087\u3063\u3068\u306e\u6c34\u306e\u7121\u99c4\u306f\u3069\u3046\u3060\u308d\u3046\uff1f\u4fbf\u5229\u3055\u304c\u91cd\u8981\u3060\u3088\u306d\u3002",B.a6,null,null),new A.aY("Hello, {username}! Consider the environment. Turning off the tap while brushing your teeth can save so much water. It's a small gesture, but it makes a big difference.","\u3053\u3093\u306b\u3061\u306f\u3001{username}\u3055\u3093\uff01\u74b0\u5883\u3092\u8003\u3048\u3066\u307f\u3066\u3002\u6b6f\u3092\u78e8\u304f\u3068\u304d\u306b\u86c7\u53e3\u3092\u9589\u3081\u308b\u3053\u3068\u3067\u3001\u305f\u304f\u3055\u3093\u306e\u6c34\u3092\u7bc0\u7d04\u3067\u304d\u307e\u3059\u3002\u5c0f\u3055\u306a\u30b8\u30a7\u30b9\u30c1\u30e3\u30fc\u3067\u3059\u304c\u3001\u5927\u304d\u306a\u9055\u3044\u3092\u751f\u307f\u51fa\u3057\u307e\u3059\u3002",B.a2,null,null),new A.aY("Ugh, really? You're going to obsess over every drop of water? Come on, it's just a little thing. Who cares?","\u3046\u30fc\u3093\u3001\u672c\u5f53\u306b\uff1f\u541b\u306f\u672c\u5f53\u306b\u3059\u3079\u3066\u306e\u6c34\u6ef4\u306b\u3053\u3060\u308f\u308b\u3064\u3082\u308a\u306a\u306e\u304b\uff1f\u3055\u3042\u3001\u305d\u308c\u306f\u3061\u3087\u3063\u3068\u3057\u305f\u3053\u3068\u3060\u3088\u3002\u8ab0\u304c\u6c17\u306b\u3059\u308b\u3093\u3060\uff1f",B.a6,null,null),new A.aY("Every drop counts, my friend. Conserving water is crucial for the health of our planet. We should not contribute to unnecessary waste.","\u3059\u3079\u3066\u306e\u6c34\u6ef4\u304c\u91cd\u8981\u3060\u3088\u3001\u53cb\u3088\u3002\u6c34\u3092\u7bc0\u7d04\u3059\u308b\u3053\u3068\u306f\u5730\u7403\u306e\u5065\u5eb7\u306b\u3068\u3063\u3066\u4e0d\u53ef\u6b20\u3060\u3002\u7121\u99c4\u306a\u6d6a\u8cbb\u306b\u5bc4\u4e0e\u3059\u3079\u304d\u3067\u306f\u306a\u3044\u3002",B.a2,null,null),new A.aY("Will you turn off the tap?","\u86c7\u53e3\u3092\u9589\u3081\u3066\u3082\u3089\u3048\u307e\u3059\u304b\uff1f",null,A.a(["Yes","No"],p),A.a(["\u306f\u3044","\u3044\u3044\u3048"],p))],q),"houseLightsArc",A.a([new A.aY("Turning off unnecessary lights is a simple act that conserves energy. Let's be mindful of our resources and help create a more sustainable world.","\u4e0d\u5fc5\u8981\u306a\u660e\u304b\u308a\u3092\u6d88\u3059\u3053\u3068\u306f\u3001\u30a8\u30cd\u30eb\u30ae\u30fc\u3092\u7bc0\u7d04\u3059\u308b\u7c21\u5358\u306a\u884c\u70ba\u3067\u3059\u3002\u79c1\u305f\u3061\u306f\u8cc7\u6e90\u306b\u6c17\u3092\u4ed8\u3051\u3001\u3088\u308a\u6301\u7d9a\u53ef\u80fd\u306a\u4e16\u754c\u3092\u7bc9\u304f\u624b\u52a9\u3051\u3092\u3057\u307e\u3057\u3087\u3046\u3002",B.a2,null,null),new A.aY("Seriously? It's just a couple of light bulbs. Leave them on; it's not like the planet will miss a few watts.","\u672c\u6c17\u3067\uff1f\u305f\u3063\u305f\u6570\u500b\u306e\u96fb\u7403\u3060\u3088\u3002\u3064\u3051\u305f\u307e\u307e\u306b\u3057\u3066\u304a\u3044\u3066\u3082\u3001\u307e\u308b\u3067\u5730\u7403\u304c\u6570\u30ef\u30c3\u30c8\u8db3\u308a\u306a\u304f\u306a\u308b\u308f\u3051\u3058\u3083\u306a\u3044\u3088\u3002",B.a6,null,null),new A.aY("Every bit of energy we save counts. By turning off the lights, you're playing a part in reducing our carbon footprint.","\u79c1\u305f\u3061\u304c\u7bc0\u7d04\u3059\u308b\u30a8\u30cd\u30eb\u30ae\u30fc\u306f\u3059\u3079\u3066\u91cd\u8981\u3067\u3059\u3002\u660e\u304b\u308a\u3092\u6d88\u3059\u3053\u3068\u3067\u3001\u3042\u306a\u305f\u306f\u79c1\u305f\u3061\u306e\u70ad\u7d20\u6392\u51fa\u91cf\u306e\u524a\u6e1b\u306b\u4e00\u5f79\u8cb7\u3063\u3066\u3044\u307e\u3059\u3002",B.a2,null,null),new A.aY("Fine, be the energy-saving champion. I bet the darkness brings you so much joy.","\u3044\u3044\u3088\u3001\u30a8\u30cd\u30eb\u30ae\u30fc\u7bc0\u7d04\u306e\u30c1\u30e3\u30f3\u30d4\u30aa\u30f3\u306b\u306a\u3063\u3066\u304f\u308c\u3002\u6697\u95c7\u304c\u541b\u306b\u305f\u304f\u3055\u3093\u306e\u559c\u3073\u3092\u3082\u305f\u3089\u3059\u3053\u3068\u3060\u308d\u3046\u3002",B.a6,null,null),new A.aY("Will you turn off the unnecessary lights?","\u4e0d\u8981\u306a\u7167\u660e\u3092\u6d88\u3057\u3066\u304f\u308c\u307e\u305b\u3093\u304b\uff1f",null,A.a(["Yes","No"],p),A.a(["\u306f\u3044","\u3044\u3044\u3048"],p))],q),"busToOfficeArc",A.a([new A.aY("[You need to commute to your office - will you choose your car or the bus?]","[\u30aa\u30d5\u30a3\u30b9\u3078\u901a\u52e4\u3059\u308b\u5fc5\u8981\u304c\u3042\u308a\u307e\u3059 - \u3042\u306a\u305f\u306f\u81ea\u5206\u306e\u8eca\u3092\u9078\u3073\u307e\u3059\u304b\u3001\u305d\u308c\u3068\u3082\u30d0\u30b9\u3092\u9078\u3073\u307e\u3059\u304b\uff1f]",null,null,null),new A.aY("Come on, why bother with the bus? Your own car is way more convenient and comfortable. Plus, who wants to deal with strangers and their germs?","\u3055\u3042\u3001\u306a\u305c\u30d0\u30b9\u3067\u60a9\u3080\u5fc5\u8981\u304c\u3042\u308b\u306e\uff1f\u3042\u306a\u305f\u81ea\u8eab\u306e\u8eca\u306e\u307b\u3046\u304c\u305a\u3063\u3068\u4fbf\u5229\u3067\u5feb\u9069\u3060\u3088\u3002\u305d\u308c\u306b\u3001\u8ab0\u304c\u898b\u77e5\u3089\u306c\u4eba\u305f\u3061\u3084\u5f7c\u3089\u306e\u7d30\u83cc\u3068\u4ed8\u304d\u5408\u3044\u305f\u3044\u3068\u601d\u3046\u3060\u308d\u3046\uff1f",B.a6,null,null),new A.aY("Choosing the bus is a great way to reduce your carbon footprint. It's more sustainable, reduces traffic, and can be a chance to meet new people.","\u30d0\u30b9\u3092\u9078\u3076\u3053\u3068\u306f\u70ad\u7d20\u6392\u51fa\u91cf\u3092\u6e1b\u3089\u3059\u7d20\u6674\u3089\u3057\u3044\u65b9\u6cd5\u3067\u3059\u3002\u305d\u308c\u306f\u3088\u308a\u6301\u7d9a\u53ef\u80fd\u3067\u3001\u4ea4\u901a\u6e0b\u6ede\u3092\u6e1b\u5c11\u3055\u305b\u3001\u65b0\u3057\u3044\u4eba\u306b\u4f1a\u3046\u30c1\u30e3\u30f3\u30b9\u306b\u3082\u306a\u308a\u307e\u3059\u3002",B.a2,null,null),new A.aY("Seriously? You're going to cram yourself into a bus with strangers? Who cares about a little extra emissions?","\u672c\u6c17\u3067\uff1f\u898b\u77e5\u3089\u306c\u4eba\u305f\u3061\u3068\u4e00\u7dd2\u306b\u30d0\u30b9\u306b\u8a70\u3081\u8fbc\u3080\u3064\u3082\u308a\u306a\u306e\uff1f\u3061\u3087\u3063\u3068\u3057\u305f\u8ffd\u52a0\u306e\u6392\u51fa\u7269\u306a\u3093\u3066\u8ab0\u3082\u6c17\u306b\u3057\u306a\u3044\u3088\u3002",B.a6,null,null),new A.aY("Every small choice matters, {username}. By driving your car, you contribute to traffic and air pollution. Let's strive for a more eco-friendly commute.","\u3059\u3079\u3066\u306e\u5c0f\u3055\u306a\u9078\u629e\u304c\u91cd\u8981\u3067\u3059\u3001{username}\u3055\u3093\u3002\u8eca\u3067\u901a\u52e4\u3059\u308b\u3053\u3068\u3067\u3001\u3042\u306a\u305f\u306f\u4ea4\u901a\u6e0b\u6ede\u3084\u5927\u6c17\u6c5a\u67d3\u306b\u5bc4\u4e0e\u3057\u307e\u3059\u3002\u3088\u308a\u30a8\u30b3\u30d5\u30ec\u30f3\u30c9\u30ea\u30fc\u306a\u901a\u52e4\u3092\u76ee\u6307\u3057\u307e\u3057\u3087\u3046\u3002",B.a2,null,null),new A.aY("What do you choose?","\u3042\u306a\u305f\u306f\u4f55\u3092\u9078\u3073\u307e\u3059\u304b\uff1f",null,A.a(["Bus","Car"],p),A.a(["\u30d0\u30b9","\u8eca"],p))],q),"tacoArc",A.a([new A.aY("[You ate a Taco]","[\u30bf\u30b3\u3092\u98df\u3079\u307e\u3057\u305f]",null,null,null),new A.aY("Hey, toss that taco wrapper wherever! Who cares about a little litter?","\u306d\u3048\u3001\u305d\u306e\u30bf\u30b3\u306e\u5305\u307f\u7d19\u306f\u3069\u3053\u306b\u3067\u3082\u6295\u3052\u3066\u3057\u307e\u3048\uff01\u3061\u3087\u3063\u3068\u3057\u305f\u30b4\u30df\u306a\u3093\u3066\u8ab0\u3082\u6c17\u306b\u3057\u306a\u3044\u3088\u3002",B.a6,null,null),new A.aY("Oh no {username}, let's not litter. Proper disposal is essential. Use the dustbin to keep our surroundings clean and protect the environment.","\u3042\u3042\u3001\u3044\u3044\u3048\u3001{username}\u3055\u3093\u3001\u30b4\u30df\u3092\u6368\u3066\u306a\u3044\u3067\u304f\u3060\u3055\u3044\u3002\u9069\u5207\u306a\u51e6\u5206\u304c\u91cd\u8981\u3067\u3059\u3002\u30b4\u30df\u7bb1\u3092\u4f7f\u3063\u3066\u5468\u56f2\u3092\u304d\u308c\u3044\u306b\u4fdd\u3061\u3001\u74b0\u5883\u3092\u5b88\u308a\u307e\u3057\u3087\u3046\u3002",B.a2,null,null),new A.aY("Seriously? It's just a taco wrapper. What harm can it do lying around for a bit?","\u672c\u6c17\u3067\uff1f\u305f\u3060\u306e\u30bf\u30b3\u306e\u5305\u307f\u7d19\u3060\u3088\u3002\u3061\u3087\u3063\u3068\u5bdd\u305d\u3079\u3063\u3066\u3044\u3066\u3082\u4f55\u306e\u5bb3\u304c\u3042\u308b\u3093\u3060\uff1f",B.a6,null,null),new A.aY("Every piece of litter contributes to pollution. By using the dustbin, you show respect for your environment and set a positive example.","\u3059\u3079\u3066\u306e\u30b4\u30df\u304c\u6c5a\u67d3\u306b\u5bc4\u4e0e\u3057\u307e\u3059\u3002\u30b4\u30df\u7bb1\u3092\u4f7f\u3046\u3053\u3068\u3067\u3001\u3042\u306a\u305f\u306f\u74b0\u5883\u306b\u5bfe\u3059\u308b\u5c0a\u91cd\u3092\u793a\u3057\u3001\u826f\u3044\u4f8b\u3092\u63d0\u4f9b\u3057\u307e\u3059\u3002",B.a2,null,null),new A.aY("Will you use the dustbin?","\u6700\u5f8c\u306e\u884c\u306e\u7ffb\u8a33\u3082\u8ffd\u52a0\u3057\u307e\u3059\u304b\uff1f",null,A.a(["Yes","No"],p),A.a(["\u306f\u3044","\u3044\u3044\u3048"],p))],q),"officePlantationArc",A.a([new A.aY("[Your colleagues are going on a tree plantation activity and want you to join]","[\u540c\u50da\u305f\u3061\u306f\u6a39\u6728\u690d\u6a39\u6d3b\u52d5\u306b\u53c2\u52a0\u3057\u3001\u3042\u306a\u305f\u3082\u4e00\u7dd2\u306b\u884c\u304f\u3088\u3046\u306b\u8a98\u3063\u3066\u3044\u307e\u3059]",null,null,null),new A.aY("Tree planting? How clich\xe9. Why bother with dirt and sweat when you could be doing something more fun?","\u6a39\u6728\u690d\u6a39\uff1f\u3069\u308c\u307b\u3069\u9673\u8150\u306a\u3053\u3068\u304b\u3002\u697d\u3057\u3044\u3053\u3068\u304c\u3067\u304d\u308b\u3068\u304d\u306b\u3001\u306a\u305c\u6c5a\u308c\u3068\u6c57\u3092\u304b\u304f\u5fc5\u8981\u304c\u3042\u308b\u306e\u304b\uff1f",B.a6,null,null),new A.aY("What a wonderful opportunity, {username}! Joining your colleagues for a tree plantation activity can make a positive impact on the environment!","\u7d20\u6674\u3089\u3057\u3044\u6a5f\u4f1a\u3060\u306d\u3001{username}\u3055\u3093\uff01\u540c\u50da\u305f\u3061\u3068\u4e00\u7dd2\u306b\u6a39\u6728\u690d\u6a39\u6d3b\u52d5\u306b\u53c2\u52a0\u3059\u308b\u3053\u3068\u306f\u3001\u74b0\u5883\u306b\u826f\u3044\u5f71\u97ff\u3092\u4e0e\u3048\u308b\u3053\u3068\u304c\u3067\u304d\u307e\u3059\uff01",B.a2,null,null),new A.aY("Seriously? You're actually going to waste your time planting trees? Do you really think one sapling is going to make a difference?","\u672c\u6c17\u3067\uff1f\u672c\u5f53\u306b\u6642\u9593\u3092\u7121\u99c4\u306b\u3057\u3066\u6728\u3092\u690d\u3048\u308b\u3064\u3082\u308a\u306a\u306e\uff1f\u4e00\u672c\u306e\u82d7\u6728\u304c\u4f55\u304b\u5909\u3048\u308b\u3068\u672c\u6c17\u3067\u601d\u3063\u3066\u3044\u308b\u306e\u304b\uff1f",B.a6,null,null),new A.aY("Every tree planted is a step toward a greener future. By participating, you're contributing to a positive change in the local ecosystem.","\u690d\u3048\u3089\u308c\u305f\u3059\u3079\u3066\u306e\u6728\u306f\u3001\u3088\u308a\u7dd1\u8c4a\u304b\u306a\u672a\u6765\u306b\u5411\u3051\u305f\u4e00\u6b69\u3067\u3059\u3002\u53c2\u52a0\u3059\u308b\u3053\u3068\u3067\u3001\u3042\u306a\u305f\u306f\u5730\u5143\u306e\u751f\u614b\u7cfb\u306b\u30dd\u30b8\u30c6\u30a3\u30d6\u306a\u5909\u5316\u3092\u3082\u305f\u3089\u3057\u3066\u3044\u307e\u3059\u3002",B.a2,null,null),new A.aY("Will you join the tree plantation activity?","\u690d\u6a39\u6d3b\u52d5\u306b\u53c2\u52a0\u3057\u307e\u305b\u3093\u304b\uff1f",null,A.a(["Yes","No"],p),A.a(["\u306f\u3044","\u3044\u3044\u3048"],p))],q)],o,n))
$.aCR.sHe(A.aD(["falseintroArc",A.a([new A.aY("Or choose chaos, and see the town face the consequences of indulgence. It's your call!","\u3042\u308b\u3044\u306f\u6df7\u6c8c\u306b\u8eab\u3092\u59d4\u306d\u3001\u753a\u304c\u653e\u7e26\u306e\u7d50\u679c\u306b\u76f4\u9762\u3059\u308b\u69d8\u5b50\u3092\u3054\u89a7\u304f\u3060\u3055\u3044\u3002\u9078\u629e\u306f\u3042\u306a\u305f\u6b21\u7b2c\u3067\u3059\u3002",B.a6,null,null)],q),"truebathroomArc",A.a([new A.aY("Thank you, {username}! Small actions like these contribute to water conservation.","\u3042\u308a\u304c\u3068\u3046\u3001{username}\u3055\u3093\uff01\u3053\u308c\u3089\u306e\u5c0f\u3055\u306a\u884c\u52d5\u306f\u6c34\u306e\u4fdd\u5b58\u306b\u8ca2\u732e\u3057\u307e\u3059\u3002",B.a2,null,null),new A.aY("Seriously? You're not going to win any popularity contests by being a water-saving hero. It's just a drop in the ocean, literally!","\u672c\u6c17\u3067\uff1f\u6c34\u3092\u7bc0\u7d04\u3059\u308b\u30d2\u30fc\u30ed\u30fc\u3067\u4eba\u6c17\u30b3\u30f3\u30c6\u30b9\u30c8\u306b\u52dd\u3064\u3064\u3082\u308a\u306f\u306a\u3044\u3067\u3057\u3087\u3046\u3002\u6587\u5b57\u901a\u308a\u5927\u6d77\u306e\u4e00\u6ef4\u3067\u3059\u3088\uff01",B.a6,null,null),new A.aY("Every drop ripples, my friend. By making conscious choices, you inspire others to do the same!","\u53cb\u3088\u3001\u3059\u3079\u3066\u306e\u6ef4\u304c\u6ce2\u7d0b\u3092\u5e83\u3052\u307e\u3059\u3002\u610f\u8b58\u7684\u306a\u9078\u629e\u3092\u3059\u308b\u3053\u3068\u3067\u3001\u3042\u306a\u305f\u306f\u4ed6\u306e\u4eba\u306b\u3082\u540c\u3058\u3053\u3068\u3092\u3059\u308b\u3088\u3046\u306b\u30a4\u30f3\u30b9\u30d1\u30a4\u30a2\u3057\u307e\u3059\uff01",B.a2,null,null)],q),"falsebathroomArc",A.a([new A.aY("A little water down the drain won't hurt anyone. We're not living in a drought, are we?","\u5c11\u3057\u306e\u6c34\u304c\u6392\u6c34\u3055\u308c\u3066\u3082\u8ab0\u3082\u50b7\u3064\u304d\u307e\u305b\u3093\u3002\u79c1\u305f\u3061\u306f\u5e72\u3070\u3064\u3067\u306f\u306a\u3044\u3067\u3059\u3088\u306d\uff1f",B.a6,null,null),new A.aY("It might be a drop, but every drop adds up, {username}. Conserving water is a responsibility we all share. Let's make choices that benefit not just us, but the entire ecosystem","\u305d\u308c\u306f\u4e00\u6ef4\u304b\u3082\u3057\u308c\u307e\u305b\u3093\u304c\u3001\u3059\u3079\u3066\u306e\u6ef4\u304c\u7a4d\u307f\u91cd\u306a\u308a\u307e\u3059\u3002\u6c34\u3092\u7bc0\u7d04\u3059\u308b\u3053\u3068\u306f\u79c1\u305f\u3061\u5168\u54e1\u306e\u8cac\u4efb\u3067\u3059\u3002\u79c1\u305f\u3061\u306f\u81ea\u5206\u3060\u3051\u3067\u306a\u304f\u3001\u5168\u751f\u614b\u7cfb\u306b\u5229\u76ca\u3092\u3082\u305f\u3089\u3059\u9078\u629e\u3092\u3057\u307e\u3057\u3087\u3046\u3002",B.a2,null,null)],q),"truehouseLightsArc",A.a([new A.aY("Well done, {username}! Your choice to switch off the lights is commendable. It not only saves energy but also helps create a more sustainable living environment.","\u3088\u304f\u3084\u308a\u307e\u3057\u305f\u3001{username}\u3055\u3093\uff01\u30e9\u30a4\u30c8\u3092\u6d88\u3059\u9078\u629e\u306f\u8cde\u8cdb\u306b\u5024\u3057\u307e\u3059\u3002\u305d\u308c\u306f\u30a8\u30cd\u30eb\u30ae\u30fc\u3092\u7bc0\u7d04\u3059\u308b\u3060\u3051\u3067\u306a\u304f\u3001\u3088\u308a\u6301\u7d9a\u53ef\u80fd\u306a\u751f\u6d3b\u74b0\u5883\u3092\u4f5c\u308a\u51fa\u3059\u306e\u306b\u3082\u5f79\u7acb\u3061\u307e\u3059\u3002",B.a2,null,null)],q),"falsehouseLightsArc",A.a([new A.aY("Ah, who cares about a few extra kilowatts? It's not like the environment can feel the burn!","\u3042\u3042\u3001\u6570\u30ad\u30ed\u30ef\u30c3\u30c8\u306e\u4f59\u5206\u306a\u3053\u3068\u306a\u3093\u3066\u8ab0\u3082\u6c17\u306b\u3057\u307e\u305b\u3093\u3002\u307e\u308b\u3067\u74b0\u5883\u304c\u305d\u308c\u3092\u611f\u3058\u308b\u304b\u306e\u3088\u3046\u3067\u3059\u306d\uff01",B.a6,null,null),new A.aY("It's disappointing to see the lights left on, {username}. Wasting energy has consequences, and unfortunately, our environment pays the price.","\u30e9\u30a4\u30c8\u3092\u3064\u3051\u305f\u307e\u307e\u306b\u3059\u308b\u306e\u306f\u304c\u3063\u304b\u308a\u3067\u3059\u3001{username}\u3055\u3093\u3002\u30a8\u30cd\u30eb\u30ae\u30fc\u306e\u6d6a\u8cbb\u306b\u306f\u7d50\u679c\u304c\u4f34\u3044\u307e\u3059\u3002\u6b8b\u5ff5\u306a\u304c\u3089\u3001\u79c1\u305f\u3061\u306e\u74b0\u5883\u304c\u305d\u306e\u4ee3\u511f\u3092\u652f\u6255\u3044\u307e\u3059\u3002",B.a2,null,null)],q),"truebusToOfficeArc",A.a([new A.aY("Congratulations on choosing the bus, {username}! Public transportation is an excellent choice for a cleaner and more sustainable commute.","\u30d0\u30b9\u3092\u9078\u3093\u3067\u304a\u3081\u3067\u3068\u3046\u3054\u3056\u3044\u307e\u3059\u3001{username}\u3055\u3093\uff01\u516c\u5171\u4ea4\u901a\u6a5f\u95a2\u306f\u3088\u308a\u6e05\u6f54\u3067\u6301\u7d9a\u53ef\u80fd\u306a\u901a\u52e4\u306e\u512a\u308c\u305f\u9078\u629e\u80a2\u3067\u3059\u3002",B.a2,null,null),new A.aY("Fine, be the bus adventurer. I hope you enjoy the extra time it takes, not to mention the inconvenience.","\u3044\u3044\u3088\u3001\u30d0\u30b9\u306e\u5192\u967a\u8005\u306b\u306a\u3063\u3066\u304f\u308c\u3002\u4f59\u5206\u306a\u6642\u9593\u3092\u697d\u3057\u3093\u3067\u304f\u308c\u308b\u3068\u3044\u3044\u306d\u3001\u4e0d\u4fbf\u3055\u306f\u8a00\u3046\u307e\u3067\u3082\u3042\u308a\u307e\u305b\u3093\u3002",B.a6,null,null),new A.aY("The bus may take a bit longer, but the environmental benefits and reduced stress on the road are worth it!","\u30d0\u30b9\u306f\u5c11\u3057\u6642\u9593\u304c\u304b\u304b\u308b\u304b\u3082\u3057\u308c\u307e\u305b\u3093\u304c\u3001\u74b0\u5883\u3078\u306e\u5229\u76ca\u3068\u9053\u8def\u306e\u30b9\u30c8\u30ec\u30b9\u306e\u8efd\u6e1b\u306f\u4fa1\u5024\u304c\u3042\u308a\u307e\u3059\uff01",B.a2,null,null)],q),"falsebusToOfficeArc",A.a([new A.aY("Ah, the freedom of your own car! No need to wait for that crowded bus. Who cares about a little extra pollution, right?","\u3042\u3042\u3001\u81ea\u5206\u306e\u8eca\u306e\u81ea\u7531\uff01\u6df7\u96d1\u3057\u305f\u30d0\u30b9\u3092\u5f85\u3064\u5fc5\u8981\u306f\u3042\u308a\u307e\u305b\u3093\u3002\u5c11\u3057\u306e\u8ffd\u52a0\u306e\u6c5a\u67d3\u306a\u3093\u3066\u8ab0\u3082\u6c17\u306b\u3057\u307e\u305b\u3093\u3088\u306d\uff1f",B.a6,null,null)],q),"truetacoArc",A.a([new A.aY("Well done, {username}! Choosing to use the dustbin helps maintain a clean environment. Small actions like these make a big difference.","\u3088\u304f\u3084\u308a\u307e\u3057\u305f\u3001{username}\u3055\u3093\uff01\u30b4\u30df\u7bb1\u3092\u4f7f\u3046\u9078\u629e\u306f\u304d\u308c\u3044\u306a\u74b0\u5883\u3092\u7dad\u6301\u3059\u308b\u306e\u306b\u5f79\u7acb\u3061\u307e\u3059\u3002\u3053\u308c\u3089\u306e\u5c0f\u3055\u306a\u884c\u52d5\u306f\u5927\u304d\u306a\u9055\u3044\u3092\u751f\u307f\u51fa\u3057\u307e\u3059\u3002",B.a2,null,null)],q),"falsetacoArc",A.a([new A.aY("Who wants to be the neat freak? It's just one wrapper; the world won't end.","\u8ab0\u304c\u6e05\u6f54\u597d\u304d\u3067\u3044\u305f\u304c\u308b\u3093\u3060\uff1f\u305f\u3063\u305f\u4e00\u3064\u306e\u5305\u307f\u7d19\u3060\u3088\u3002\u4e16\u754c\u306f\u7d42\u308f\u3089\u306a\u3044\u3055\u3002",B.a6,null,null),new A.aY("Unfortunately, by littering, you've added to the pollution. Let's strive to keep our world clean by using the dustbin.","\u6b8b\u5ff5\u306a\u3053\u3068\u306b\u3001\u30b4\u30df\u3092\u6368\u3066\u308b\u3053\u3068\u3067\u6c5a\u67d3\u304c\u5897\u3048\u3066\u3057\u307e\u3044\u307e\u3057\u305f\u3002\u30b4\u30df\u7bb1\u3092\u4f7f\u3063\u3066\u4e16\u754c\u3092\u6e05\u6f54\u306b\u4fdd\u3064\u3088\u3046\u52aa\u529b\u3057\u307e\u3057\u3087\u3046\u3002",B.a2,null,null)],q),"trueofficePlantationArc",A.a([new A.aY("Well done, {username}! Your choice to join the tree plantation activity is commendable. It's these collective efforts that lead to a more sustainable and beautiful world.","\u3088\u304f\u3084\u308a\u307e\u3057\u305f\u3001{username}\u3055\u3093\uff01\u6a39\u6728\u690d\u6a39\u6d3b\u52d5\u306b\u53c2\u52a0\u3059\u308b\u3053\u3068\u3092\u9078\u3093\u3060\u3042\u306a\u305f\u306b\u656c\u610f\u3092\u8868\u3057\u307e\u3059\u3002\u3053\u308c\u3089\u306e\u96c6\u5408\u7684\u306a\u52aa\u529b\u304c\u3001\u3088\u308a\u6301\u7d9a\u53ef\u80fd\u3067\u7f8e\u3057\u3044\u4e16\u754c\u306b\u3064\u306a\u304c\u308a\u307e\u3059\u3002",B.a2,null,null)],q),"falseofficePlantationArc",A.a([new A.aY("It's disheartening to see the missed opportunity. Tree planting has a cascading positive effect on the environment, and your participation could have made a significant difference.","\u9003\u3057\u305f\u6a5f\u4f1a\u3092\u898b\u308b\u306e\u306f\u5fc3\u304c\u6c88\u307f\u307e\u3059\u306d\u3002\u6a39\u6728\u690d\u6a39\u306f\u74b0\u5883\u306b\u9023\u9396\u7684\u306a\u826f\u3044\u5f71\u97ff\u3092\u4e0e\u3048\u3001\u3042\u306a\u305f\u306e\u53c2\u52a0\u304c\u91cd\u8981\u306a\u9055\u3044\u3092\u3082\u305f\u3089\u3059\u53ef\u80fd\u6027\u304c\u3042\u308a\u307e\u3057\u305f\u3002",B.a2,null,null),new A.aY("Never mind {username}, you can now do something more enjoyable.","\u6c17\u306b\u3057\u306a\u3044\u3067\u3001{username}\u3055\u3093\u3001\u4eca\u306f\u3082\u3063\u3068\u697d\u3057\u3044\u3053\u3068\u304c\u3067\u304d\u307e\u3059\u3088\u3002",B.a6,null,null),new A.aY("Enjoyment is subjective, but the positive impact of tree planting is undeniable. Let's strive to make choices that benefit both us and the world around us.","\u697d\u3057\u307f\u306f\u4e3b\u89b3\u7684\u3067\u3059\u304c\u3001\u6a39\u6728\u690d\u6a39\u306e\u30dd\u30b8\u30c6\u30a3\u30d6\u306a\u5f71\u97ff\u306f\u5426\u5b9a\u3067\u304d\u307e\u305b\u3093\u3002\u79c1\u305f\u3061\u306f\u81ea\u5206\u305f\u3061\u3068\u5468\u308a\u306e\u4e16\u754c\u306e\u4e21\u65b9\u306b\u5229\u76ca\u3092\u3082\u305f\u3089\u3059\u9078\u629e\u3092\u3057\u307e\u3057\u3087\u3046\u3002",B.a2,null,null)],q)],o,n))
$.aIQ.sHe(A.aD([100,A.a([new A.aY("What a delightful day in EcoVille!","\u30a8\u30b3\u30d3\u30eb\u3067\u7d20\u6674\u3089\u3057\u3044\u65e5\u3060\u306d\uff01",B.aR,null,null),new A.aY("I can feel the positive vibes in the air!","\u7a7a\u6c17\u4e2d\u306b\u30dd\u30b8\u30c6\u30a3\u30d6\u306a\u96f0\u56f2\u6c17\u3092\u611f\u3058\u307e\u3059\uff01",B.aR,null,null),new A.aY("Absolutely no pollution today! Clean air is a blessing.","\u4eca\u65e5\u306f\u307e\u3063\u305f\u304f\u6c5a\u67d3\u304c\u3042\u308a\u307e\u305b\u3093\uff01\u304d\u308c\u3044\u306a\u7a7a\u6c17\u306f\u6075\u307f\u3067\u3059\u3002",B.aR,null,null)],q),80,A.a([new A.aY("It's a bit hazy today, isn't it?","\u4eca\u65e5\u306f\u5c11\u3057\u971e\u3093\u3067\u3044\u307e\u3059\u306d\uff1f",B.aR,null,null),new A.aY("Breathing in the fresh air of EcoVille!","\u30a8\u30b3\u30d3\u30eb\u306e\u65b0\u9bae\u306a\u7a7a\u6c17\u3092\u5438\u3046\uff01",B.aR,null,null),new A.aY("No pollution today! Good job, everyone.","\u4eca\u65e5\u306f\u307e\u3063\u305f\u304f\u6c5a\u67d3\u304c\u3042\u308a\u307e\u305b\u3093\uff01\u307f\u3093\u306a\u3088\u304f\u3084\u3063\u305f\u3002",B.aR,null,null)],q),60,A.a([new A.aY("The air quality could use some improvement, don't you think?","\u7a7a\u6c17\u306e\u8cea\u306f\u6539\u5584\u306e\u4f59\u5730\u304c\u3042\u308a\u305d\u3046\u3060\u306d\u3001\u3069\u3046\u601d\u3046\uff1f",B.aR,null,null),new A.aY("More green spaces would really make EcoVille shine.","\u3082\u3063\u3068\u7dd1\u306e\u30b9\u30da\u30fc\u30b9\u304c\u3042\u308c\u3070\u3001\u30a8\u30b3\u30d3\u30eb\u304c\u672c\u5f53\u306b\u8f1d\u304f\u3067\u3057\u3087\u3046\u3002",B.aR,null,null),new A.aY("Let's join hands to make our environment healthier and vibrant!","\u4e00\u7dd2\u306b\u624b\u3092\u7d44\u3093\u3067\u3001\u74b0\u5883\u3092\u3088\u308a\u5065\u5eb7\u3067\u6d3b\u6c17\u306b\u6e80\u3061\u305f\u3082\u306e\u306b\u3057\u307e\u3057\u3087\u3046\uff01",B.aR,null,null)],q),40,A.a([new A.aY("The pollution levels are rising; we need to act now.","\u6c5a\u67d3\u30ec\u30d9\u30eb\u304c\u4e0a\u6607\u3057\u3066\u3044\u307e\u3059\u3002\u4eca\u3059\u3050\u884c\u52d5\u3059\u308b\u5fc5\u8981\u304c\u3042\u308a\u307e\u3059\u3002",B.aR,null,null),new A.aY("Our beautiful EcoVille deserves better. Time to make changes!","\u7f8e\u3057\u3044\u30a8\u30b3\u30d3\u30eb\u306f\u3082\u3063\u3068\u826f\u3044\u3082\u306e\u3092\u5024\u3059\u308b\u3002\u5909\u66f4\u306e\u6642\u3067\u3059\uff01",B.aR,null,null),new A.aY("Eco-conscious choices can turn things around for us!","\u30a8\u30b3\u610f\u8b58\u306e\u3042\u308b\u9078\u629e\u304c\u79c1\u305f\u3061\u306e\u72b6\u6cc1\u3092\u597d\u8ee2\u3055\u305b\u308b\u3053\u3068\u304c\u3067\u304d\u307e\u3059\uff01",B.aR,null,null)],q),20,A.a([new A.aY("It's getting hard to breathe in this environment.","\u3053\u306e\u74b0\u5883\u3067\u606f\u3092\u3059\u308b\u306e\u304c\u96e3\u3057\u304f\u306a\u3063\u3066\u304d\u305f\u3002",B.aR,null,null),new A.aY("Garbage everywhere. We can't let this continue.","\u3069\u3053\u306b\u3067\u3082\u30b4\u30df\u304c\u6563\u4e71\u3057\u3066\u3044\u307e\u3059\u3002\u3053\u308c\u3092\u7d9a\u3051\u308b\u308f\u3051\u306b\u306f\u3044\u304d\u307e\u305b\u3093\u3002",B.aR,null,null),new A.aY("Maybe it's time to consider moving to a cleaner place.","\u3082\u3057\u304b\u3057\u305f\u3089\u3001\u3088\u308a\u6e05\u6f54\u306a\u5834\u6240\u306b\u5f15\u3063\u8d8a\u3059\u6642\u304b\u3082\u3057\u308c\u307e\u305b\u3093\u3002",B.aR,null,null)],q),0,A.a([new A.aY("Everything is lost.","\u3059\u3079\u3066\u304c\u5931\u308f\u308c\u307e\u3057\u305f\u3002",B.aR,null,null)],q)],t.S,n))
